class Solution {
public:
    string lastSubstring(string s) {
        string res = s.substr(0, 1);
        for (int i = 1; i < s.length(); i++) {
            if (s[i] >= res.back()) {
                res = res.substr(0, i) + s.substr(i);
            }
        }
        return res;
    }
};
```

